// On interroge le premier noeud nommé "Config API" pour récupérer les clés
const config = $('Config API').first().json;

const AK = config.AK;
const AS = config.AS;
const CK = config.CK;


const method = 'GET';
const url = 'https://eu.api.ovh.com/1.0/domain/zone/';
const body = '';

// 2. Extraction du timestamp OVH
let ovhTime = 0;
if (typeof $json === 'number') ovhTime = $json;
else if (typeof $json === 'string') ovhTime = parseInt($json, 10);
else if ($json && $json.data) ovhTime = parseInt($json.data, 10);
else {
    const rawValue = JSON.stringify($json).replace(/\D/g, ''); 
    ovhTime = parseInt(rawValue, 10);
}
const timestamp = Math.floor(ovhTime);

// 3. Chaîne exacte à signer
const toSign = `${AS}+${CK}+${method}+${url}+${body}+${timestamp}`;

// 4. Fonction algorithme SHA-1 (100% Pure JavaScript)
function sha1(s) {
    var chrsz = 8;
    var hexcase = 0;
    function hex_sha1(s) { return binb2hex(core_sha1(str2binb(s), s.length * chrsz)); }
    function core_sha1(x, len) {
        x[len >> 5] |= 0x80 << (24 - len % 32);
        x[((len + 64 >> 9) << 4) + 15] = len;
        var w = Array(80), a = 1732584193, b = -271733879, c = -1732584194, d = 271733878, e = -1009589776;
        for (var i = 0; i < x.length; i += 16) {
            var olda = a, oldb = b, oldc = c, oldd = d, olde = e;
            for (var j = 0; j < 80; j++) {
                if (j < 16) w[j] = x[i + j];
                else w[j] = rol(w[j - 3] ^ w[j - 8] ^ w[j - 14] ^ w[j - 16], 1);
                var t = safe_add(safe_add(rol(a, 5), sha1_ft(j, b, c, d)), safe_add(safe_add(e, w[j]), sha1_kt(j)));
                e = d; d = c; c = rol(b, 30); b = a; a = t;
            }
            a = safe_add(a, olda); b = safe_add(b, oldb); c = safe_add(c, oldc); d = safe_add(d, oldd); e = safe_add(e, olde);
        }
        return Array(a, b, c, d, e);
    }
    function sha1_ft(t, b, c, d) {
        if (t < 20) return (b & c) | ((~b) & d);
        if (t < 40) return b ^ c ^ d;
        if (t < 60) return (b & c) | (b & d) | (c & d);
        return b ^ c ^ d;
    }
    function sha1_kt(t) {
        return (t < 20) ? 1518500249 : (t < 40) ? 1859775393 : (t < 60) ? -1894007588 : -899497514;
    }
    function safe_add(x, y) {
        var lsw = (x & 0xFFFF) + (y & 0xFFFF);
        var msw = (x >> 16) + (y >> 16) + (lsw >> 16);
        return (msw << 16) | (lsw & 0xFFFF);
    }
    function rol(num, cnt) {
        return (num << cnt) | (num >>> (32 - cnt));
    }
    function str2binb(str) {
        var bin = Array();
        var mask = (1 << chrsz) - 1;
        for (var i = 0; i < str.length * chrsz; i += chrsz)
            bin[i >> 5] |= (str.charCodeAt(i / chrsz) & mask) << (24 - i % 32);
        return bin;
    }
    function binb2hex(binarray) {
        var hex_tab = hexcase ? "0123456789ABCDEF" : "0123456789abcdef";
        var str = "";
        for (var i = 0; i < binarray.length * 4; i++) {
            str += hex_tab.charAt((binarray[i >> 2] >> ((3 - i % 4) * 8 + 4)) & 0xF) +
                   hex_tab.charAt((binarray[i >> 2] >> ((3 - i % 4) * 8)) & 0xF);
        }
        return str;
    }
    return hex_sha1(s);
}

// 5. Création de la signature au format attendu par OVH
const signature = `$1$${sha1(toSign)}`;

return [{
  json: {
    url: url,
    AK: AK,
    CK: CK,
    timestamp: timestamp,
    signature: signature
  }
}];

// On interroge le premier noeud nommé "Config API" pour récupérer les clés
const config = $('Config API').first().json;

const AK = config.AK;
const AS = config.AS;
const CK = config.CK;

const method = 'GET';

// 2. Extraction de la liste des domaines
let domains = [];
for (const item of $input.all()) {
    if (!item || !item.json) continue;
    const data = item.json;
    if (Array.isArray(data)) domains.push(...data);
    else if (typeof data === 'object') domains.push(...Object.values(data));
    else if (typeof data === 'string') domains.push(data);
}

domains = domains.filter(d => typeof d === 'string' && d.includes('.'));
if (domains.length === 0) throw new Error("Aucun domaine n'a été trouvé.");

const results = [];

// 3. Fonction algorithme SHA-1
function sha1(s) {
    var chrsz = 8; var hexcase = 0;
    function hex_sha1(s) { return binb2hex(core_sha1(str2binb(s), s.length * chrsz)); }
    function core_sha1(x, len) {
        x[len >> 5] |= 0x80 << (24 - len % 32); x[((len + 64 >> 9) << 4) + 15] = len;
        var w = Array(80), a = 1732584193, b = -271733879, c = -1732584194, d = 271733878, e = -1009589776;
        for (var i = 0; i < x.length; i += 16) {
            var olda = a, oldb = b, oldc = c, oldd = d, olde = e;
            for (var j = 0; j < 80; j++) {
                if (j < 16) w[j] = x[i + j]; else w[j] = rol(w[j - 3] ^ w[j - 8] ^ w[j - 14] ^ w[j - 16], 1);
                var t = safe_add(safe_add(rol(a, 5), sha1_ft(j, b, c, d)), safe_add(safe_add(e, w[j]), sha1_kt(j)));
                e = d; d = c; c = rol(b, 30); b = a; a = t;
            }
            a = safe_add(a, olda); b = safe_add(b, oldb); c = safe_add(c, oldc); d = safe_add(d, oldd); e = safe_add(e, olde);
        }
        return Array(a, b, c, d, e);
    }
    function sha1_ft(t, b, c, d) { if (t < 20) return (b & c) | ((~b) & d); if (t < 40) return b ^ c ^ d; if (t < 60) return (b & c) | (b & d) | (c & d); return b ^ c ^ d; }
    function sha1_kt(t) { return (t < 20) ? 1518500249 : (t < 40) ? 1859775393 : (t < 60) ? -1894007588 : -899497514; }
    function safe_add(x, y) { var lsw = (x & 0xFFFF) + (y & 0xFFFF); var msw = (x >> 16) + (y >> 16) + (lsw >> 16); return (msw << 16) | (lsw & 0xFFFF); }
    function rol(num, cnt) { return (num << cnt) | (num >>> (32 - cnt)); }
    function str2binb(str) { var bin = Array(); var mask = (1 << chrsz) - 1; for (var i = 0; i < str.length * chrsz; i += chrsz) bin[i >> 5] |= (str.charCodeAt(i / chrsz) & mask) << (24 - i % 32); return bin; }
    function binb2hex(binarray) { var hex_tab = hexcase ? "0123456789ABCDEF" : "0123456789abcdef"; var str = ""; for (var i = 0; i < binarray.length * 4; i++) { str += hex_tab.charAt((binarray[i >> 2] >> ((3 - i % 4) * 8 + 4)) & 0xF) + hex_tab.charAt((binarray[i >> 2] >> ((3 - i % 4) * 8)) & 0xF); } return str; }
    return hex_sha1(s);
}

// 4. La Boucle : On interroge l'API OVH EN DIRECT pour chaque domaine
for (const domain of domains) {

    // Requête HTTP intégrée pour obtenir l'heure exacte à l'instant T
    const timeResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://eu.api.ovh.com/1.0/auth/time',
    });

    // On extrait le timestamp de la réponse
    const timestamp = Math.floor(parseInt(timeResponse, 10));

    const url = `https://eu.api.ovh.com/1.0/domain/zone/${domain}/export`;
    const toSign = `${AS}+${CK}+${method}+${url}++${timestamp}`;
    const signature = `$1$${sha1(toSign)}`;

    results.push({
        json: {
            domain: domain,
            url: url,
            AK: AK,
            CK: CK,
            timestamp: timestamp, 
            signature: signature
        }
    });
}

return results;

// 1. On recule de 30 jours par rapport à la date du jour
const limitDate = new Date();
limitDate.setDate(limitDate.getDate() - 30);

const filesToDelete = [];

// 2. On parcourt vos 3 items
for (const item of $input.all()) {
    const folderName = item.json.name;

    // Sécurité : On vérifie que le nom est bien au format Date (YYYY-MM-DD)
    if (/^\d{4}-\d{2}-\d{2}$/.test(folderName)) {

        const folderDate = new Date(folderName);

        // Si le dossier est PLUS VIEUX que notre limite de 30 jours...
        if (folderDate < limitDate) {
            // ... on l'ajoute à la liste des condamnés
            filesToDelete.push(item);
        }
    }
}

// 3. On transmet le résultat au noeud Delete
return filesToDelete;
